package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void testSetNumberToNumberStrategy_withValidStrategy_shouldSetFieldAndReturnThis() throws Exception {
    ToNumberStrategy mockStrategy = mock(ToNumberStrategy.class);

    GsonBuilder returned = gsonBuilder.setNumberToNumberStrategy(mockStrategy);

    assertSame(gsonBuilder, returned);

    // Use reflection to verify private field numberToNumberStrategy is set
    Field field = GsonBuilder.class.getDeclaredField("numberToNumberStrategy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);
    assertSame(mockStrategy, fieldValue);
  }

  @Test
  public void testSetNumberToNumberStrategy_withNullStrategy_shouldThrowNullPointerException() {
    NullPointerException exception = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.setNumberToNumberStrategy(null);
    });
    // The message from Objects.requireNonNull may be null, so just check exception is thrown
    // Remove the assertNotNull on message to fix the test
  }

  @Test
  public void testSetNumberToNumberStrategy_reflectionInvoke() throws Exception {
    ToNumberStrategy mockStrategy = mock(ToNumberStrategy.class);

    Method method = GsonBuilder.class.getDeclaredMethod("setNumberToNumberStrategy", ToNumberStrategy.class);
    method.setAccessible(true);

    Object returned = method.invoke(gsonBuilder, mockStrategy);
    assertSame(gsonBuilder, returned);

    Field field = GsonBuilder.class.getDeclaredField("numberToNumberStrategy");
    field.setAccessible(true);
    assertSame(mockStrategy, field.get(gsonBuilder));
  }
}
